import { useState } from 'react';
import { COLORS } from './data';
import { supabase } from './supabase';
import { LogIn, Eye, EyeOff, AlertCircle, UserPlus, Mail, ArrowLeft, Loader2, CheckCircle2 } from 'lucide-react';

export const APP_LOGO_SRC = 'data:image/png;base64,';

export function AppLogo({ size = 44 }) {
  return <img src={APP_LOGO_SRC} alt="Logo" style={{ width: size, height: size, borderRadius: 10, objectFit: 'contain' }} />;
}

export default function LoginPage() {
  const [mode, setMode] = useState('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [shaking, setShaking] = useState(false);

  const shake = () => { setShaking(true); setTimeout(() => setShaking(false), 500); };

  const handleLogin = async (e) => {
    e.preventDefault();
    if (!email || !password) { setError('Please enter email and password'); shake(); return; }
    setError(''); setMessage(''); setLoading(true);
    const { error } = await supabase.auth.signInWithPassword({ email: email.trim(), password });
    if (error) { setError(error.message); shake(); }
    setLoading(false);
  };

  const handleSignup = async (e) => {
    e.preventDefault();
    if (!email || !password) { setError('Please enter email and password'); shake(); return; }
    if (password.length < 6) { setError('Password must be at least 6 characters'); shake(); return; }
    if (password !== confirmPassword) { setError('Passwords do not match'); shake(); return; }
    setError(''); setMessage(''); setLoading(true);
    const { data, error } = await supabase.auth.signUp({ email: email.trim(), password });
    if (error) { setError(error.message); shake(); }
    else if (data?.user?.identities?.length === 0) { setError('An account with this email already exists'); shake(); }
    else { setMessage('Check your email for a confirmation link, then come back and sign in!'); }
    setLoading(false);
  };

  const handleForgot = async (e) => {
    e.preventDefault();
    if (!email) { setError('Please enter your email address'); shake(); return; }
    setError(''); setMessage(''); setLoading(true);
    const { error } = await supabase.auth.resetPasswordForEmail(email.trim(), {
      redirectTo: window.location.origin,
    });
    if (error) { setError(error.message); shake(); }
    else { setMessage('Password reset email sent! Check your inbox.'); }
    setLoading(false);
  };

  const switchMode = (newMode) => { setMode(newMode); setError(''); setMessage(''); };

  return (
    <div style={ls.root}>
      <style>{`
        @keyframes fadeInUp { from { opacity: 0; transform: translateY(30px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes shake { 0%, 100% { transform: translateX(0); } 20%, 60% { transform: translateX(-8px); } 40%, 80% { transform: translateX(8px); } }
        @keyframes float { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-8px); } }
        @keyframes gradientShift { 0% { background-position: 0% 50%; } 50% { background-position: 100% 50%; } 100% { background-position: 0% 50%; } }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
      `}</style>
      <div style={ls.bgGradient} />
      <div style={ls.bgPattern} />
      <div style={{ ...ls.card, animation: shaking ? 'shake 0.4s ease' : 'fadeInUp 0.6s ease' }}>
        <div style={ls.logoSection}>
          <div style={{ animation: 'float 3s ease-in-out infinite' }}><AppLogo size={80} /></div>
          <h1 style={ls.title}>Gas Safety Certificates</h1>
          <p style={ls.subtitle}>CP12 \u2014 Landlord Gas Safety Records</p>
        </div>

        {mode !== 'forgot' && (
          <div style={ls.tabRow}>
            <button onClick={() => switchMode('login')} style={{ ...ls.tab, ...(mode === 'login' ? ls.tabActive : {}) }}>
              <LogIn size={15} /> Sign In
            </button>
            <button onClick={() => switchMode('signup')} style={{ ...ls.tab, ...(mode === 'signup' ? ls.tabActive : {}) }}>
              <UserPlus size={15} /> Sign Up
            </button>
          </div>
        )}

        {mode === 'forgot' && (
          <button onClick={() => switchMode('login')} style={ls.backBtn}>
            <ArrowLeft size={16} /> Back to Sign In
          </button>
        )}

        {message && <div style={ls.successBox}><CheckCircle2 size={16} /><span>{message}</span></div>}
        {error && <div style={ls.errorBox}><AlertCircle size={16} /><span>{error}</span></div>}

        {mode === 'login' && (
          <form onSubmit={handleLogin} style={ls.form}>
            <div style={ls.fieldGroup}>
              <label style={ls.label}>Email</label>
              <input type="email" value={email} onChange={e => { setEmail(e.target.value); setError(''); }}
                placeholder="you@example.com" style={ls.input} autoComplete="email" autoFocus />
            </div>
            <div style={ls.fieldGroup}>
              <label style={ls.label}>Password</label>
              <div style={{ position: 'relative' }}>
                <input type={showPassword ? 'text' : 'password'} value={password}
                  onChange={e => { setPassword(e.target.value); setError(''); }}
                  placeholder="Your password" style={ls.input} autoComplete="current-password" />
                <button type="button" onClick={() => setShowPassword(!showPassword)} style={ls.eyeButton}>
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>
            <button type="button" onClick={() => switchMode('forgot')} style={ls.forgotLink}>Forgot password?</button>
            <button type="submit" disabled={loading} style={{ ...ls.submitButton, opacity: loading ? 0.7 : 1 }}>
              {loading ? <Loader2 size={18} style={{ animation: 'spin 1s linear infinite' }} /> : <LogIn size={18} />}
              {loading ? 'Signing in...' : 'Sign In'}
            </button>
          </form>
        )}

        {mode === 'signup' && (
          <form onSubmit={handleSignup} style={ls.form}>
            <div style={ls.fieldGroup}>
              <label style={ls.label}>Email</label>
              <input type="email" value={email} onChange={e => { setEmail(e.target.value); setError(''); }}
                placeholder="you@example.com" style={ls.input} autoComplete="email" autoFocus />
            </div>
            <div style={ls.fieldGroup}>
              <label style={ls.label}>Password</label>
              <div style={{ position: 'relative' }}>
                <input type={showPassword ? 'text' : 'password'} value={password}
                  onChange={e => { setPassword(e.target.value); setError(''); }}
                  placeholder="Min. 6 characters" style={ls.input} autoComplete="new-password" />
                <button type="button" onClick={() => setShowPassword(!showPassword)} style={ls.eyeButton}>
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>
            <div style={ls.fieldGroup}>
              <label style={ls.label}>Confirm Password</label>
              <input type={showPassword ? 'text' : 'password'} value={confirmPassword}
                onChange={e => { setConfirmPassword(e.target.value); setError(''); }}
                placeholder="Re-enter password" style={ls.input} autoComplete="new-password" />
            </div>
            <button type="submit" disabled={loading} style={{ ...ls.submitButton, opacity: loading ? 0.7 : 1 }}>
              {loading ? <Loader2 size={18} style={{ animation: 'spin 1s linear infinite' }} /> : <UserPlus size={18} />}
              {loading ? 'Creating account...' : 'Create Account'}
            </button>
          </form>
        )}

        {mode === 'forgot' && (
          <form onSubmit={handleForgot} style={ls.form}>
            <p style={{ fontSize: 14, color: COLORS.muted, marginBottom: 6, lineHeight: 1.6 }}>
              Enter your email and we will send you a link to reset your password.
            </p>
            <div style={ls.fieldGroup}>
              <label style={ls.label}>Email</label>
              <input type="email" value={email} onChange={e => { setEmail(e.target.value); setError(''); }}
                placeholder="you@example.com" style={ls.input} autoComplete="email" autoFocus />
            </div>
            <button type="submit" disabled={loading} style={{ ...ls.submitButton, opacity: loading ? 0.7 : 1 }}>
              {loading ? <Loader2 size={18} style={{ animation: 'spin 1s linear infinite' }} /> : <Mail size={18} />}
              {loading ? 'Sending...' : 'Send Reset Link'}
            </button>
          </form>
        )}

        <p style={ls.footer}>Secured with Supabase</p>
      </div>
    </div>
  );
}

const ls = {
  root: { minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative', overflow: 'hidden', fontFamily: "'Outfit', sans-serif", padding: 20 },
  bgGradient: { position: 'fixed', inset: 0, background: 'linear-gradient(135deg, #1a1a2e 0%, #e65100 50%, #bf360c 100%)', backgroundSize: '400% 400%', animation: 'gradientShift 15s ease infinite' },
  bgPattern: { position: 'fixed', inset: 0, backgroundImage: 'radial-gradient(rgba(255,255,255,0.06) 1px, transparent 1px)', backgroundSize: '28px 28px' },
  card: { position: 'relative', zIndex: 1, background: '#ffffff', borderRadius: 24, padding: '40px 36px', width: '100%', maxWidth: 420, boxShadow: '0 24px 80px rgba(0,0,0,0.3)' },
  logoSection: { display: 'flex', flexDirection: 'column', alignItems: 'center', marginBottom: 28 },
  title: { fontSize: 24, fontWeight: 800, color: COLORS.primary, marginTop: 16, letterSpacing: -0.5, textAlign: 'center' },
  subtitle: { fontSize: 13, color: COLORS.muted, marginTop: 4, textAlign: 'center' },
  tabRow: { display: 'flex', gap: 4, marginBottom: 20, background: COLORS.inputBg, borderRadius: 10, padding: 4 },
  tab: { flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6, padding: '10px 16px', borderRadius: 8, border: 'none', background: 'transparent', color: COLORS.muted, fontSize: 14, fontWeight: 600, cursor: 'pointer', fontFamily: "'Outfit', sans-serif", transition: 'all 0.2s' },
  tabActive: { background: '#fff', color: COLORS.accent, boxShadow: '0 2px 8px rgba(0,0,0,0.08)' },
  backBtn: { display: 'flex', alignItems: 'center', gap: 6, marginBottom: 16, background: 'transparent', border: 'none', color: COLORS.accent, fontSize: 14, fontWeight: 600, cursor: 'pointer', fontFamily: "'Outfit', sans-serif", padding: 0 },
  form: { display: 'flex', flexDirection: 'column', gap: 16 },
  fieldGroup: { display: 'flex', flexDirection: 'column', gap: 6 },
  label: { fontSize: 13, fontWeight: 600, color: COLORS.text, letterSpacing: 0.2 },
  input: { width: '100%', padding: '12px 14px', borderRadius: 10, border: '1.5px solid ' + COLORS.border, background: COLORS.inputBg, fontSize: 15, color: COLORS.text, fontFamily: "'Outfit', sans-serif", outline: 'none', boxSizing: 'border-box' },
  eyeButton: { position: 'absolute', right: 12, top: '50%', transform: 'translateY(-50%)', background: 'transparent', border: 'none', color: COLORS.muted, cursor: 'pointer', padding: 4, display: 'flex' },
  forgotLink: { background: 'transparent', border: 'none', color: COLORS.accent, fontSize: 13, fontWeight: 600, cursor: 'pointer', fontFamily: "'Outfit', sans-serif", textAlign: 'right', padding: 0, marginTop: -8 },
  errorBox: { display: 'flex', alignItems: 'flex-start', gap: 8, padding: '10px 14px', borderRadius: 10, background: COLORS.redBg, border: '1px solid ' + COLORS.red + '30', color: COLORS.red, fontSize: 13, fontWeight: 500, marginBottom: 4 },
  successBox: { display: 'flex', alignItems: 'flex-start', gap: 8, padding: '10px 14px', borderRadius: 10, background: COLORS.greenBg, border: '1px solid ' + COLORS.green + '30', color: COLORS.green, fontSize: 13, fontWeight: 500, marginBottom: 4 },
  submitButton: { display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 10, padding: '14px 24px', borderRadius: 12, background: COLORS.accent, border: 'none', color: '#ffffff', fontSize: 16, fontWeight: 700, cursor: 'pointer', fontFamily: "'Outfit', sans-serif", marginTop: 4, boxShadow: '0 4px 14px rgba(230,81,0,0.3)', transition: 'all 0.2s' },
  footer: { textAlign: 'center', fontSize: 12, color: COLORS.muted, marginTop: 24, letterSpacing: 0.5 },
};
